#include <bits/stdc++.h>
using namespace std;
#define int long long
int n,m,ans=0x3fffffff;
bool check(int rm,int rn,int r,int h){
	int vmin=0,vmax=0;
	for(int i=1;i<=rm;i++){
		vmin+=i*i*i;
		vmax+=r*r*h;
		r--,h--;
	}
	return rn>=vmin&&rn<=vmax;
}
void dfs(int rm,int rn,int r,int h,int s){
	if(rm==0){
		if(rn==0){
			ans=min(ans,s);
		}
		return;
	}
	if(!check(rm,rn,r,h)) return;
	if(s+2*rn/(int)sqrt(rn)>=ans) return;
	for(int r2=min((int)sqrt(rn),r);r2>=rm;r2--){
		for(int h2=min(rn/r2/r2,h);h2>=rm;h2--){
			dfs(rm-1,rn-r2*r2*h2,r2-1,h2-1,s+2*r2*h2+(rm==m)*r2*r2);
		}
	}
}
signed main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m;
	dfs(m,n,sqrt(n),n,0);
	ans==0x3fffffff?cout<<0:cout<<ans;
	return 0;
}
